Step 4 — Implement
- I'll use a `TrieNode` class with a `children` map and `isEndOfWord` boolean.
- Use a recursive `dfs` helper for the search to handle the '.' wildcard.

```javascript
class TrieNode {
    constructor() {
        this.children = new Map();
        this.isEndOfWord = false;
    }
}

class WordDictionary {
    constructor() {
        this.root = new TrieNode();
    }

    addWord(word) {
        let node = this.root;
        for (const char of word) {
            if (!node.children.has(char)) {
                node.children.set(char, new TrieNode());
            }
            node = node.children.get(char);
        }
        node.isEndOfWord = true;
    }

    search(word) {
        const dfs = (index, node) => {
            if (index === word.length) {
                return node.isEndOfWord;
            }

            const char = word[index];
            if (char === '.') {
                for (const childNode of node.children.values()) {
                    if (dfs(index + 1, childNode)) return true;
                }
            } else {
                if (!node.children.has(char)) return false;
                return dfs(index + 1, node.children.get(char));
            }
            return false;
        };

        return dfs(0, this.root);
    }
}

// Time Complexity: 
// addWord: O(L) where L is word length
// search: O(26^N) worst case for dots, but O(L) for standard words
// Space Complexity: O(T) where T is total characters in all words
```

Staff tip: "I'll mention that using a Map instead of a fixed-size array makes the structure more flexible for non-English characters while maintaining O(1) average lookup."
